// // This register loads the input data (D) on the falling edge of the clock if the load enable (load) is low.
module register (
    input clk,
    input load,
    input reset,
    input [3:0] D,
    output reg [3:0] Q
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            Q <= 4'b0000;
        else if (load)
            Q <= D;
    end

endmodule
